export type scoutMcpServersLogicType = MakeLogicType<
    scoutMcpServersLogicValues,
    scoutMcpServersLogicActions,
    Record<string, any>,
    scoutMcpServersLogicMeta
>

export const scoutMcpServersLogic = kea<scoutMcpServersLogicType>([
    path(['scenes', 'inbox', 'logics', 'scoutMcpServersLogic']),
    connect({
        values: [teamLogic, ['currentTeamId']],
    }),
    loaders(({ values }) => ({
        serviceAccounts: [
            [] as MCPServiceAccountApi[],
            {
                loadServiceAccounts: async () => {
                    if (values.currentTeamId === null) {
                        return []
                    }
                    const response = await mcpGatewayServiceAccountsList(String(values.currentTeamId), { limit: 500 })
                    return response.results
                },
            },
        ],
    })),
    selectors({
        scoutAccount: [
            (s) => [s.serviceAccounts],
            (serviceAccounts: MCPServiceAccountApi[]): MCPServiceAccountApi | null =>
                serviceAccounts.find((account) => account.agent_key === 'scout') ?? null,
        ],
        isScoutMcpAccessEnabled: [
            (s) => [s.scoutAccount],
            (scoutAccount: MCPServiceAccountApi | null): boolean =>
                scoutAccount?.status === 'active' && scoutAccount.product_enabled,
        ],
        scoutServers: [
            (s) => [s.scoutAccount],
            (scoutAccount: MCPServiceAccountApi | null): MCPServiceAccountServerApi[] => [
                ...(scoutAccount?.servers ?? []),
            ],
        ],
        readyScoutServers: [
            (s) => [s.scoutServers],
            (scoutServers: MCPServiceAccountServerApi[]): MCPServiceAccountServerApi[] =>
                scoutServers.filter((server) => server.connection_state === 'ready'),
        ],
        availableScoutServers: [
            (s) => [s.readyScoutServers, s.isScoutMcpAccessEnabled],
            (
                readyScoutServers: MCPServiceAccountServerApi[],
                isScoutMcpAccessEnabled: boolean
            ): MCPServiceAccountServerApi[] => (isScoutMcpAccessEnabled ? readyScoutServers : []),
        ],
        scoutServersNeedingSetup: [
            (s) => [s.scoutServers],
            (scoutServers: MCPServiceAccountServerApi[]): MCPServiceAccountServerApi[] =>
                scoutServers.filter((server) => server.connection_state !== 'ready'),
        ],
        scoutServersLoading: [
            (s) => [s.serviceAccountsLoading],
            (serviceAccountsLoading: boolean): boolean => serviceAccountsLoading,
        ],
    }),
    subscriptions(({ actions }) => ({
        currentTeamId: () => actions.loadServiceAccounts(),
    })),
])
